import React, { useEffect } from 'react';
import { View, Text, Button } from 'react-native';
import { PaymentRequest } from 'react-native-payments';
import { DeviceInfo } from 'react-native-device-info';

const paymentProviders = {
  applePay: 'apple-pay',
  googlePay: 'google-pay',
};

const PaymentModule = () => {
  const [deviceStatus, setDeviceStatus] = React.useState(null);
  const [paymentMethod, setPaymentMethod] = React.useState(null);

  useEffect(() => {
    checkDeviceIntegrity();
  }, []);

  const checkDeviceIntegrity = async () => {
    try {
      const deviceInfo = await DeviceInfo.getDeviceId();
      const isRooted = await DeviceInfo.isRooted();
      const isJailbroken = await DeviceInfo.isJailbroken();

      if (isRooted || isJailbroken) {
        setDeviceStatus('UNTRUSTED');
      } else {
        setDeviceStatus('TRUSTED');
      }
    } catch (error) {
      console.error(error);
    }
  };

  const handlePayment = async () => {
    try {
      if (!deviceStatus || deviceStatus !== 'TRUSTED') {
        alert('Please ensure your device is trusted to proceed with payment.');
        return;
      }

      const paymentRequest = new PaymentRequest(paymentProviders.applePay, {
        amount: 10.99,
        currencyCode: 'USD',
        description: 'Test Purchase',
      });

      await paymentRequest.show();
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <View>
      <Text>Device Status: {deviceStatus}</Text>
      <Button title="Make Payment" onPress={handlePayment} />
    </View>
  );
};

